import{_ as i,c as e,a,o as n}from"./app-CEcM0piI.js";const d={};function t(l,s){return n(),e("div",null,s[0]||(s[0]=[a(`<p>并不像关系型数据库那样在数据表创建之初就确定好列 它支持的数据结构非常松散，是一种类似于JSON的格式叫BSON，所以它既可以存储比较复杂的数据类型，又相当的灵活。 它是文档型数据库,其中一个数据库中有多个集合,一个集合中有多个文档 集合类似于关系型数据库中的表,文档类似于关系型数据库中的行</p><table><thead><tr><th>SQL术语/概念</th><th>MongoDB术语/概念</th><th>解释/说明</th></tr></thead><tbody><tr><td>database</td><td>database</td><td>数据库</td></tr><tr><td>table</td><td>collection</td><td>数据库表/集合</td></tr><tr><td>row</td><td>document</td><td>数据记录行/文档</td></tr><tr><td>column</td><td>field</td><td>数据字段/域</td></tr><tr><td>index</td><td>index</td><td>索引</td></tr><tr><td>table joins</td><td></td><td>表连接,MongoDB不支持</td></tr><tr><td></td><td>嵌入文档</td><td>MongoDB通过嵌入式文档来替代多表连接</td></tr><tr><td>primary key</td><td>primary key</td><td>主键，MongoDB中主键不是自己设置的而是会自动将_id字段设置为主键</td></tr><tr><td>index</td><td>index</td><td>索引</td></tr><tr><td>view</td><td>view</td><td>视图</td></tr><tr><td>table joins</td><td>lookup</td><td>聚合操作</td></tr></tbody></table><p>启动</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mongod --dbpath D:\\MongoDB\\data\\db --logpath D:\\MongoDB\\logs\\mongodb.log</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>添加到windows服务</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>mongod --dbpath &quot;D:\\MongoDB\\data\\db&quot; --logpath &quot;D:\\MongoDB\\log\\mongo.log&quot; -install -serviceName &quot;MongoDB&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果没有权限需要使用管理员身份打开cmd</p><p>有一些数据库名是保留的，可以直接访问这些有特殊作用的数据库。</p><ul><li>admin：从权限的角度来看，这是&quot;root&quot;数据库。要是将一个用户添加到这个数据库，这个用户自动继承所有数据库的权限。一些特定的服务器端命令也只能从这个数据库运行，比如列出所有的数据库或者关闭服务器。</li><li>local：这个数据永远不会被复制，可以用来存储限于本地单台服务器的任意集合</li><li>config:当Mongo用于分片设置时，config数据库在内部使用，用于保存分片的相关信息。</li></ul><h1 id="bson" tabindex="-1"><a class="header-anchor" href="#bson"><span>BSON</span></a></h1><p>SON( Binary Serialized Document Format) 是一种二进制形式的存储格式，采用了类似于 C 语言结构体的名称、对表示方法，支持内嵌的文档对象和数组对象，具有轻量性、可遍历性、高效性的特点，可以有效描述非结构化数据和结构化数据。</p><p>BSON是一种类json的一种二进制形式的存储格式，简称Binary JSON，它和JSON一样，支持内嵌的文档对象和数组对象，但是BSON有JSON没有的一些数据类型，如Date和BinData类型。 BSON可以做为网络数据交换的一种存储形式，这个有点类似于Google的Protocol Buffer，但是BSON是一种schema-less的存储形式，它的优点是灵活性高，但它的缺点是空间利用率不是很理想</p><p>BSON有三个特点：轻量性、可遍历性、高效性。</p><h4 id="bson中的数据类型" tabindex="-1"><a class="header-anchor" href="#bson中的数据类型"><span>BSON中的数据类型</span></a></h4><table><thead><tr><th>数据类型</th><th>描述</th><th>举例</th></tr></thead><tbody><tr><td>字符串</td><td>UTF-8字符串都可表示为字符串类型的数据</td><td><code>{&quot;x&quot; :&quot;foobar&quot;}</code></td></tr><tr><td>对象id</td><td>对象id是文档的12字节的唯一ID</td><td><code>{&quot;X&quot; :ObjectId()}</code></td></tr><tr><td>布尔值</td><td>真或者假：true或者false</td><td><code>{&quot;x&quot;:true}</code></td></tr><tr><td>数组</td><td>值的集合或者列表可以表示成数组</td><td><code>{&quot;x&quot; : [&quot;a&quot;, &quot;b&quot;, &quot;c&quot;]}</code></td></tr><tr><td>32位整数</td><td>类型不可用。JavaScript仅支持64位浮点数，shell中默认会32位整数会被自动转换。</td><td>shell是不支持该类型的转换成64位浮点数</td></tr><tr><td>64位整数</td><td>不支持这个类型。shell会使用一个特殊的内嵌文档</td><td>shell是不支持该类型的转换成64位浮点数</td></tr><tr><td>64位浮点数</td><td>shell中的数字就是这一种类型</td><td><code>{&quot;x&quot;: 3.14159, &quot;y&quot;: 3}</code></td></tr><tr><td>null</td><td>表示空值或者未定义的对象</td><td><code>{&quot;x&quot;:null}</code></td></tr><tr><td>undefined</td><td>文档中也可以使用未定义类型</td><td><code>{&quot;x&quot;:undefined}</code></td></tr><tr><td>符号</td><td>shell不支持，shell会将数据库中的符号类型的数据自动转换成字符串</td><td></td></tr><tr><td>正则表达式</td><td>文档中可以包含正则表达式，采用JavaScript的正则式表达式语法</td><td><code>{&quot;x&quot;:/foobar/i}</code></td></tr><tr><td>代码</td><td>文档中还可以包含JavaScript代码</td><td><code>{&quot;x&quot; : function(){/* ....*/</code>}</td></tr><tr><td>二进制数据</td><td>二进制数据可以由任意字节的串组成，不过shell中据无法使用</td><td></td></tr><tr><td>最大值/最小值</td><td>BSON包括一个特殊类型，表示可能的最大值。shell中没有这个类型。<br></td><td></td></tr></tbody></table><h1 id="数据库操作" tabindex="-1"><a class="header-anchor" href="#数据库操作"><span>数据库操作</span></a></h1><p><strong>使用数据库或创建数据库</strong> 如果要使用的数据库不存在则创建</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>use 数据库名字</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>创建数据库操作先是创建在内存中,并没有创建到硬盘中,此时使用查询将查询不到新建的数据库,如果对新建的数据库进行插入数据的操作时数据库会自动保存到硬盘中了</p><blockquote><p>[!warning] 注意 在MongoDB中，集合只有在内容插入后才会创建！就是说。创建集合(数据表)后要再插入一个文档（记录），集合才会真正创建。</p></blockquote><p><strong>查看有权限查看的所有数据库命令</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>show dbs</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>show databases</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>查看当前正在使用的数据库命令</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>删除数据库</strong> 删除正在使用的数据库</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.dropDatebase()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="集合操作" tabindex="-1"><a class="header-anchor" href="#集合操作"><span>集合操作</span></a></h1><p><strong>创建集合</strong></p><p>显式创建</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.createCollection(&quot;集合名&quot;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>隐式创建 当向一个集合插入文档时如果集合不存在则自动创建一个集合</p><p>通常隐式创建</p><p><strong>删除集合</strong> 删除当前正在使用数据库中的集合</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.drop()</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>db.集合名.drop()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="文档操作" tabindex="-1"><a class="header-anchor" href="#文档操作"><span>文档操作</span></a></h1><p>嵌套文档要加双引号才能找到嵌套文档内的某个字段 <strong>异常处理</strong> mongodb是支持js语法的因此也可以使用try catch进行异常处理</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>try{</span></span>
<span class="line"><span>	操作语句</span></span>
<span class="line"><span>}catch(e){</span></span>
<span class="line"><span>	print(e)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>插入文档</strong> insert只能插入一条数据 在新版本中被弃用,可以使用insertOne方法,语法一样,只需要把insert改为insertOne即可</p><ul><li>&lt;docuent or array of documents&gt;: 要插入到集合中的文档或文档数组</li><li>writeConcern: 要插入的文档的级别</li><li>ordered: 可选。类型为布尔值 如果为真，则按顺序插入数组中的文档，如果其中一个文档出现错误，MongoDB将返回而不处理数组中的其余文档。如果为假，则执行无序插入，如果其中一个文档出现错误，则继续处理数组中的主文档。在版本2.6+中默认为true</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.集合名称.insert{</span></span>
<span class="line"><span>	&lt;document orarray of documents&gt;,</span></span>
<span class="line"><span>	{</span></span>
<span class="line"><span>		writeConcern:&lt;document&gt;,</span></span>
<span class="line"><span>		ordered:&lt;boolean&gt;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>示例:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.insertOne(  </span></span>
<span class="line"><span>    {        </span></span>
<span class="line"><span>	    &quot;articleid&quot;:&quot;100000&quot;,  </span></span>
<span class="line"><span>        &quot;content&quot;:&quot;今天天气真好,阳光明媚&quot;,  </span></span>
<span class="line"><span>        &quot;userid&quot;:&quot;1001&quot;,&quot;nickname&quot;:&quot;Rose&quot;,  </span></span>
<span class="line"><span>        &quot;createtime&quot;:new Date(),  </span></span>
<span class="line"><span>        &quot;likenum&quot;:NumberInt(10),  </span></span>
<span class="line"><span>        &quot;state&quot;:null  </span></span>
<span class="line"><span>    }  </span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol><li>mongo中的数字，默认情况下是double类型，如果要存整型，必须使用函数Numberlnt(整型数字)，否则取出来就有问题了。</li><li>插入当前日期使用newDate()</li><li>插入的数据没有指定_id，会自动生成主键值</li><li>如果某字段没值，可以赋值为null，或不写该字段。</li></ol><p><strong>插入多条</strong> insertMany</p><p><strong>文档查询</strong> 不填任何参数查询的是所有</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.集合名.find()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果想要查询特定的数据需要在参数中指定BSJON数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.集合名.find({&quot;articleid&quot;: &quot;100002&quot;})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果要只想拿到符合条件的第一条数据可以使用findOne</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.集合名.findOne()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><strong>投影查询</strong> 如果要查询结果返回部分字段，则需要使用投影查询（不显示所有字段，只显示指定的字段） 如：查询结果只显示_id、userid、nickname：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.find(  </span></span>
<span class="line"><span>    {userid: &quot;1003&quot;},  </span></span>
<span class="line"><span>    {userid: 1, nickname: 1}  </span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在查询时将指定字段的值设为1,这样就可以只显示指定字段了 但这样查询即使没有指定_id也会默认查询_id字段,可以将_id的值设为0强制将其排除</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.find(  </span></span>
<span class="line"><span>    {userid: &quot;1003&quot;},  </span></span>
<span class="line"><span>    {userid: 1, nickname: 1, _id: 0}  </span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>文档更新</strong><mark>mongo链接允许全局覆盖,mongosh只允许局部修改</mark></p><ul><li>collection : 要操作的集合</li><li>query : 查询的条件</li><li>option : 修改选项</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.update(query,update,option)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><mark>不能使用_id字段进行查询</mark></p><ul><li>$set : 修改数据</li><li>$push : 用于数组添加数据</li><li>$unset : 删除<strong>字段</strong></li></ul><p>update已经被弃用,可以使用updateOne替代 update对多条指定字段一致的数据进行修改时默认只修改第一个查询到的文档,若要修改多条需要更改修改选项</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.update(</span></span>
<span class="line"><span>    {nickname: &quot;Rose&quot;},</span></span>
<span class="line"><span>    {$set: {nickname: &quot;Sunset&quot;}},</span></span>
<span class="line"><span>    {multi:true}</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>updateIOne不支持多文档同时修改,需要使用updateMany</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.updateMany(  </span></span>
<span class="line"><span>    {nickname: &quot;Rose&quot;},  </span></span>
<span class="line"><span>    {$set: {nickname: &quot;Sunset&quot;}},  </span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>示例:</p><p>局部覆盖 局部覆盖只修改了指定的元素 将articleid为100000的likenum字段设置为30020</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.updateOne(</span></span>
<span class="line"><span>    {articleid: &quot;100000&quot;},</span></span>
<span class="line"><span>    {$set: {likenum: NumberInt(30020)}}</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>全局覆盖 全局覆盖就是把原数据删除,新插入更新的数据,没有指定更新字段处为空白</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.updateOne(  </span></span>
<span class="line"><span>    {articleid: &quot;100301&quot;},  </span></span>
<span class="line"><span>    {likenum: NumberInt(1145)}  </span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>列值增长 将指定的likenum字段增长1</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.updateOne(</span></span>
<span class="line"><span>    {articleid: &quot;100000&quot;},</span></span>
<span class="line"><span>    {$inc: {likenum: NumberInt(1)}}</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>文档删除</strong> 将符合条件的文档全部删除 mongosh链接无法使用_id字段查询</p><ul><li>collection : 集合名</li><li>query : 查询出来要删除的字段</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.remove(query)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>将数据全部删除</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.remove({})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>删除_id=1的记录</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.remove({_id:&quot;1&quot;})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>已经被弃用,使用deleteOne删除第一个符合条件的文档,使用deleteMany删除所有符合条件的文档</p><h3 id="统计查询" tabindex="-1"><a class="header-anchor" href="#统计查询"><span>统计查询</span></a></h3><p>统计符合查询条件的字段数</p><ul><li>query : 查询选择条件。</li><li>options : 可选。用于修改计数的额外选项。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.count(query,options)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>count被弃用,使用countDocuments代替</p><p>查询所有</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.count()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>$match : 管道操作,将当前的结果内容传输到下一个</li><li>$group : 分组,设为null的字段不参与分组条件</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.student.aggregate([  </span></span>
<span class="line"><span>    {$match:{Age:{$gt:NumberInt(20)}}},  </span></span>
<span class="line"><span>    {$group:{_id:null,avgHeight:{$avg:&quot;$Height&quot;}}}  </span></span>
<span class="line"><span>])</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>将查询到的年龄大于20的数据传递到下面的分组取平均值</p><h3 id="分页查询" tabindex="-1"><a class="header-anchor" href="#分页查询"><span>分页查询</span></a></h3><ul><li>limit : 读取指定数量的数据</li><li>skip : 跳过指定数量的数据。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.find().limit(number).skip(number)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>skip是跳到一定数量的数据的位置开始查询</p><h3 id="排序查询" tabindex="-1"><a class="header-anchor" href="#排序查询"><span>排序查询</span></a></h3><p>sort()方法对数据进行排序，sort()方法可以通过参数指定排序的字段，并使用1和-1来指定排序的方式，其中1为升序排列，而-1是用于降序排列。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.find().sort({KEY:1})</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>db.集合名称.find().sort（排序方式）</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>根据articleid降序进行查询</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.find().sort({articleid: -1})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="正则查询" tabindex="-1"><a class="header-anchor" href="#正则查询"><span>正则查询</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.find({field：/正则表达式/})</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>db.集合.find({字段：/正则表达式/)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>查询content字段中包含阳光的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.find({content:/阳光/})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="比较查询" tabindex="-1"><a class="header-anchor" href="#比较查询"><span>比较查询</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.collection.find({&quot;field&quot;:{$gt:value}})//大于：field&gt;value</span></span>
<span class="line"><span>db.collection.find([“field&quot;:{$1t:value}})//小于：field&lt;value</span></span>
<span class="line"><span>db.collection.find([&quot;field&quot;:{$gte:value}})/大于等于：field&gt;=value</span></span>
<span class="line"><span>db.collection.find({&quot;field&quot;:{$lte:value}})/小于等于：field&lt;=value</span></span>
<span class="line"><span>db.collection.find({&quot;field&quot;:{$ne:value}})不等于：field！=value</span></span>
<span class="line"><span>db.collection.find({&quot;field&quot;:{$in:value}})包含：field包含value</span></span>
<span class="line"><span>db.collection.find({&quot;field&quot;:{$nin:value}})不包含：field不包含value</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>示例:查询likenum数大于700的数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.find({1ikenum:{$gt:NumberInt(700)}})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>多条件需要写在中括号里面,并且中间使用逗号隔开</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.comment.find({$and: [{likenum:{$gte:NumberInt(700)}},{likenum: {$1t:NumberInt(2000)}}]})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="聚合操作" tabindex="-1"><a class="header-anchor" href="#聚合操作"><span>聚合操作</span></a></h1><p>MongoDB提供了多种聚合方法，其中最常用的是<code>aggregate()</code>方法。该方法能够接受多个聚合管道阶段，每个阶段对输入文档进行处理，并将结果传递给下一个阶段。聚合框架的灵活性使得它能够处理复杂的数据处理需求。</p><p>聚合管道由一系列阶段组成，每个阶段使用一个操作符来处理输入数据。常见的管道阶段包括：</p><ul><li>$match：过滤文档，类似于查询中的find()。</li><li>$group：对文档进行分组，并计算聚合值。</li><li>$sort：对文档进行排序。</li><li>$project：重塑文档，选择需要的字段或计算新字段。</li><li>$limit：限制返回的文档数量。</li><li>$skip：跳过指定数量的文档。</li><li>$unwind：将文档中的某一个数组类型字段拆分成多条，每条包含数组中的一个值。</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>db.borrow.aggregate(</span></span>
<span class="line"><span>	{$lookup:{from:&quot;reader&quot;,loclaField:&quot;reader_id&quot;,foreignField:&quot;reader_id&quot;,as:&quot;readerinfor&quot;}}</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,112)]))}const p=i(d,[["render",t]]),c=JSON.parse('{"path":"/tools/mongodb/1/","title":"1 简介","lang":"zh-CN","frontmatter":{"title":"1 简介","createTime":"2025/06/22 10:04:20","permalink":"/tools/mongodb/1/"},"readingTime":{"minutes":10,"words":2999},"git":{"createdTime":1750599657000,"updatedTime":1750644294000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":2,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/MongoDB/1 简介.md","headers":[]}');export{p as comp,c as data};
